    aboIntro:'Many underestimate how much they pay in subscriptions. Add all your services — streaming, gym, mobile, cloud storage, etc. — and see the actual total cost. The surprise factor is big.',
    aboLHdr:'Your subscriptions', aboColName:'Service', aboColAmount:'Price (kr/mo)', aboBtnAdd:'Add', aboBtnCalc:'Calculate total cost →',
